		///<summary>
        ///Only Biatec Pool Provider can deploy and bootsrap this smart contract
        ///No_op: CALL, Opt_in: NEVER, Close_out: NEVER, Update_application: NEVER, Delete_application: NEVER
        ///</summary>
		/// <param name="assetA">Asset A ID must be lower then Asset B ID, or can be equal to Asset B ID for staking pools ABI Type is uint64  </param>
		/// <param name="assetB">Asset B ABI Type is uint64  </param>
		/// <param name="appBiatecConfigProvider">Biatec amm provider ABI Type is uint64  </param>
		/// <param name="appBiatecPoolProvider">Pool provider ABI Type is uint64  </param>
		/// <param name="txSeed">Seed transaction so that smart contract can opt in to the assets ABI Type is pay  </param>
		/// <param name="fee">Fee in base level (9 decimals). value 1_000_000_000 = 1 = 100%. 10_000_000 = 1%. 1_000_000 = 0.1% ABI Type is uint64  </param>
		/// <param name="priceMin">Min price range. At this point all assets are in asset A. ABI Type is uint64  </param>
		/// <param name="priceMax">Max price range. At this point all assets are in asset B. ABI Type is uint64  </param>
		/// <param name="currentPrice">Deployer can specify the current price for easier deployemnt. ABI Type is uint64  </param>
		/// <param name="verificationClass">Minimum verification level from the biatec identity. Level 0 means no kyc. ABI Type is uint64  </param>
		public async Task<ulong> bootstrap (PaymentTransaction txSeed,ulong assetA,ulong assetB,ulong appBiatecConfigProvider,ulong appBiatecPoolProvider,ulong fee,ulong priceMin,ulong priceMax,ulong currentPrice,ulong verificationClass, Account _tx_sender, ulong? _tx_fee = null,string _tx_note = "", ulong _tx_roundValidity = 1000, List<BoxRef>? _tx_boxes = null, List<Transaction>? _tx_transactions = null, List<ulong>? _tx_assets = null, List<ulong>? _tx_apps = null, List<Address>? _tx_accounts = null, AVM.ClientGenerator.Core.OnCompleteType _tx_callType = AVM.ClientGenerator.Core.OnCompleteType.NoOp )
		{
			_tx_boxes ??= new List<BoxRef>();
			_tx_transactions ??= new List<Transaction>();
			_tx_assets ??= new List<ulong>();
			_tx_apps ??= new List<ulong>();
			_tx_accounts ??= new List<Address>();
			_tx_transactions.AddRange(new List<Transaction> {txSeed});
			byte[] abiHandle = {43,255,250,117};
			var result = await base.CallApp(new List<object> {abiHandle,assetA,assetB,appBiatecConfigProvider,appBiatecPoolProvider,fee,priceMin,priceMax,currentPrice,verificationClass}, _tx_fee: _tx_fee,  _tx_callType: _tx_callType, _tx_roundValidity: _tx_roundValidity, _tx_note: _tx_note, _tx_sender: _tx_sender, _tx_transactions: _tx_transactions , _tx_apps: _tx_apps, _tx_assets:_tx_assets, _tx_accounts: _tx_accounts, _tx_boxes: _tx_boxes);
			var lastLogBytes = result.Last();
			if (lastLogBytes.Length < 4 || lastLogBytes[0] != 21 || lastLogBytes[1] != 31 || lastLogBytes[2] != 124 || lastLogBytes[3] != 117) throw new Exception("Invalid ABI handle");
			var lastLogReturnData = lastLogBytes.Skip(4).ToArray();
			return BitConverter.ToUInt64(ReverseIfLittleEndian(lastLogReturnData), 0);

		}

